mapper.select:
select id, tenant_id, route_code, route_name, team, alert_group, severity, receiver, group_by, group_wait_seconds, group_interval_seconds, repeat_interval_seconds, enabled, description, created_at, updated_at from batch.alert_routing_config where tenant_id = #{tenantId} and is_deleted = false
and route_code like concat('%', #{routeCode}, '%')
and team = #{team}
and severity = #{severity}
and enabled = #{enabled}
order by id desc
limit #{pageRequest.pageSize} offset (#{pageRequest.pageNo} - 1) * #{pageRequest.pageSize}

select count(1)
from batch.alert_routing_config
where tenant_id = #{tenantId}
  and is_deleted = false

    and route_code like concat('%', #{routeCode}, '%')


    and team = #{team}


    and severity = #{severity}


    and enabled = #{enabled}

select *
from batch.alert_routing_config
where tenant_id = #{tenantId}
  and is_deleted = false
  and route_code = #{routeCode}
limit 1

select *
from batch.alert_routing_config
where tenant_id = #{tenantId}
  and is_deleted = false
  and id = #{id}
limit 1

mapper.update:
update batch.alert_routing_config
set enabled = #{enabled}, updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}
  and is_deleted = false
